SELECT metric_value
FROM performance_metrics
WHERE config_id = (SELECT config_id FROM hardware_configurations WHERE config_name = 'Config A');

SELECT *
FROM hardware_configurations
WHERE performance_target LIKE '%1000%' AND TYPEOF(CAST(performance_target AS INTEGER)) = 'integer';

SELECT memory_level, latency
FROM memory_levels
WHERE latency = (SELECT MAX(latency) FROM memory_levels);

SELECT COUNT(*)
FROM memory_levels
WHERE associativity = '4-way';

SELECT memory_level, latency
FROM memory_levels
WHERE latency = (
    SELECT MAX(latency)
    FROM memory_levels
);

SELECT memory_level 
FROM memory_levels 
WHERE memory_id = (SELECT MIN(memory_id) FROM memory_levels);

SELECT QUOTE(memory_level), CAST(REPLACE(latency, 'ns', '') AS REAL) / MAX(CAST(REPLACE(latency, 'ns', '') AS REAL)) OVER() AS latency_fraction
FROM memory_levels
WHERE CAST(REPLACE(latency, 'ns', '') AS REAL) > 2;

SELECT config_name, description, hardware_version, software_version, system_architecture, performance_target 
FROM hardware_configurations 
WHERE config_id = 0;
